#include<bits/stdc++.h>
using namespace std;

int main(){
    int n,m,a[111][111],b[111][111];
    cin>>n>>m;
    for(int i=1;i<=n;i++){
        for(int j=1;j<=m;j++){
            cin>>a[i][j];
        }
    }for(int i=1;i<=n;i++){
        for(int j=1;j<=m;j++){
            if(i==1||j==1||i==n||j==m) b[i][j]=a[i][j];
            else b[i][j]=round((a[i][j]+a[i+1][j]+a[i][j+1]+a[i-1][j]+a[i][j-1])/5.0);
        }
    }
    for(int i=1;i<=n;i++){
        for(int j=1;j<=m;j++){
            cout<<b[i][j]<<" ";
        }cout<<"\n";
    }
    return 0;
}
